import { useEffect, useMemo, useState } from "react";
import { motion } from "framer-motion";
import { bookService } from "../services/api";
import MessageBanner from "../components/MessageBanner";
import { isAdmin } from "../utils/auth";

const PLACEHOLDER_IMAGE =
  "https://images.unsplash.com/photo-1521587760476-6c12a4b040da?auto=format&fit=crop&w=900&q=80";

const initialForm = {
  title: "",
  author: "",
  ISBN: "",
  quantity: "",
  image: ""
};

const LoadingSpinner = () => (
  <div className="flex items-center justify-center py-16">
    <div className="w-10 h-10 border-4 border-slate-300 border-t-slate-800 rounded-full animate-spin" />
  </div>
);

const EmptyBooksState = () => (
  <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-10 text-center">
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="1.5"
      className="w-16 h-16 mx-auto text-slate-400 mb-4"
    >
      <path d="M4 19.5A2.5 2.5 0 016.5 17H20" />
      <path d="M6.5 2H20v17H6.5A2.5 2.5 0 014 16.5v-12A2.5 2.5 0 016.5 2z" />
    </svg>
    <h3 className="text-lg font-semibold text-slate-800">No books available</h3>
    <p className="text-slate-500 mt-1">Start by adding a few books to build your library catalog.</p>
  </div>
);

const cardContainerVariants = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: {
      staggerChildren: 0.06
    }
  }
};

const cardVariants = {
  hidden: { opacity: 0, y: 18 },
  show: { opacity: 1, y: 0, transition: { duration: 0.25 } }
};

const BooksPage = () => {
  const adminView = isAdmin();
  const [books, setBooks] = useState([]);
  const [form, setForm] = useState(initialForm);
  const [editingBookId, setEditingBookId] = useState("");
  const [searchTerm, setSearchTerm] = useState("");
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const loadBooks = async () => {
    try {
      setError("");
      setLoading(true);
      const res = await bookService.getAll();
      setBooks(res.data || []);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to fetch books");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadBooks();
  }, []);

  const filteredBooks = useMemo(() => {
    const query = searchTerm.trim().toLowerCase();
    if (!query) return books;

    return books.filter((book) => {
      const title = String(book.title || "").toLowerCase();
      const author = String(book.author || "").toLowerCase();
      return title.includes(query) || author.includes(query);
    });
  }, [books, searchTerm]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setError("");
      setMessage("");
      const payload = {
        ...form,
        quantity: Number(form.quantity)
      };

      if (editingBookId) {
        await bookService.update(editingBookId, payload);
        setMessage("Book updated successfully");
      } else {
        await bookService.create(payload);
        setMessage("Book added successfully");
      }

      setForm(initialForm);
      setEditingBookId("");
      await loadBooks();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to save book");
    }
  };

  const handleDelete = async (id) => {
    try {
      setError("");
      setMessage("");
      await bookService.remove(id);
      setMessage("Book deleted successfully");
      await loadBooks();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to delete book");
    }
  };

  const handleEdit = (book) => {
    setEditingBookId(book._id);
    setForm({
      title: book.title || "",
      author: book.author || "",
      ISBN: book.ISBN || "",
      quantity: String(book.quantity ?? ""),
      image: book.image || ""
    });
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-4">
        <div>
          <h2 className="text-3xl font-semibold text-slate-900">Books Catalog</h2>
          <p className="text-slate-500 mt-1">Browse and manage the library collection.</p>
        </div>
        <div className="w-full md:w-80">
          <input
            type="text"
            className="w-full border border-slate-300 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-slate-400"
            placeholder="Search by title or author..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <MessageBanner message={message} />
      <MessageBanner message={error} variant="error" />

      {adminView && (
        <form onSubmit={handleSubmit} className="bg-white shadow-sm border border-slate-200 rounded-2xl p-5">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">
            {editingBookId ? "Edit Book" : "Add New Book"}
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-5 gap-3">
            <input
              className="border rounded-lg px-3 py-2"
              name="title"
              placeholder="Title"
              value={form.title}
              onChange={handleChange}
              required
            />
            <input
              className="border rounded-lg px-3 py-2"
              name="author"
              placeholder="Author"
              value={form.author}
              onChange={handleChange}
              required
            />
            <input
              className="border rounded-lg px-3 py-2"
              name="ISBN"
              placeholder="ISBN"
              value={form.ISBN}
              onChange={handleChange}
              required
            />
            <input
              className="border rounded-lg px-3 py-2"
              name="quantity"
              type="number"
              min="0"
              placeholder="Quantity"
              value={form.quantity}
              onChange={handleChange}
              required
            />
            <input
              className="border rounded-lg px-3 py-2"
              name="image"
              placeholder="Image URL (optional)"
              value={form.image}
              onChange={handleChange}
            />
          </div>
          <div className="mt-4 flex gap-2">
            <button
              type="submit"
              className="bg-slate-900 text-white px-4 py-2 rounded-lg hover:bg-slate-800 transition-colors"
            >
              {editingBookId ? "Update Book" : "Add Book"}
            </button>
            {editingBookId && (
              <button
                type="button"
                className="bg-slate-200 text-slate-800 px-4 py-2 rounded-lg hover:bg-slate-300 transition-colors"
                onClick={() => {
                  setEditingBookId("");
                  setForm(initialForm);
                }}
              >
                Cancel
              </button>
            )}
          </div>
        </form>
      )}

      {loading ? (
        <LoadingSpinner />
      ) : filteredBooks.length === 0 ? (
        <EmptyBooksState />
      ) : (
        <motion.div
          variants={cardContainerVariants}
          initial="hidden"
          animate="show"
          className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-5"
        >
          {filteredBooks.map((book) => (
            <motion.article
              key={book._id}
              variants={cardVariants}
              whileHover={{ y: -4, scale: 1.01 }}
              className="bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-all duration-200 overflow-hidden"
            >
              <div className="h-52 bg-slate-100">
                <img
                  src={book.image || PLACEHOLDER_IMAGE}
                  alt={book.title}
                  className="w-full h-full object-cover"
                  onError={(e) => {
                    e.currentTarget.src = PLACEHOLDER_IMAGE;
                  }}
                />
              </div>
              <div className="p-4 space-y-2">
                <h3 className="text-lg font-semibold text-slate-900">{book.title}</h3>
                <p className="text-slate-600">by {book.author}</p>
                <p className="text-sm text-slate-500">ISBN: {book.ISBN}</p>
                <div className="flex items-center justify-between pt-1">
                  <span className="text-sm text-slate-600">Available Copies</span>
                  <span className="text-sm font-semibold text-emerald-700">{book.availableCopies}</span>
                </div>

                {adminView && (
                  <div className="flex gap-2 pt-3">
                    <button
                      type="button"
                      className="flex-1 bg-amber-500 text-white px-3 py-2 rounded-lg hover:bg-amber-400 transition-colors"
                      onClick={() => handleEdit(book)}
                    >
                      Edit
                    </button>
                    <button
                      type="button"
                      className="flex-1 bg-red-600 text-white px-3 py-2 rounded-lg hover:bg-red-500 transition-colors"
                      onClick={() => handleDelete(book._id)}
                    >
                      Delete
                    </button>
                  </div>
                )}
              </div>
            </motion.article>
          ))}
        </motion.div>
      )}
    </div>
  );
};

export default BooksPage;
